import{_ as l,o as a,c as d,ag as i}from"./chunks/framework.DXGyWiRo.js";const e="/media/202410/1_1729221574.png",r="/media/202410/2_1729221597.png",o="/media/202410/3_1729221625.png",p="/media/202410/4_1729221635.png",n="/media/202410/5_1729221647.png",s="/media/202410/6_1729221655.png",c="/media/202410/7_1729221667.png",_="/media/202410/8_1729221676.png",h="/media/202410/9_1729221686.png",m="/media/202410/10_1729221694.png",u="/media/202410/11_1729221703.png",b="/media/202410/12_1729221711.png",x="/media/202410/13_1729221719.png",g="/media/202410/14_1729221728.png",I=JSON.parse('{"title":"文档问答","description":"","frontmatter":{"title":"文档问答"},"headers":[],"relativePath":"custom-biz/qa-library/document-qa.md","filePath":"custom-biz/qa-library/document-qa.md","lastUpdated":null}'),q={name:"custom-biz/qa-library/document-qa.md"};function f(k,t,P,y,A,T){return a(),d("div",null,[...t[0]||(t[0]=[i('<h2 id="_1-文档问答说明" tabindex="-1">1.文档问答说明 <a class="header-anchor" href="#_1-文档问答说明" aria-label="Permalink to &quot;1.文档问答说明&quot;">​</a></h2><p>文档问答，是基于星火大模型知识库方案，高校检索文档信息，准确回答专业问题。支持开发者自定义知识点拆分逻辑、查看已拆分的知识点、编辑管理知识点。</p><p>上传文档支持两种方式：</p><ul><li>本地文档</li><li>在线文档</li></ul><h2 id="文档问答分类" tabindex="-1">文档问答分类 <a class="header-anchor" href="#文档问答分类" aria-label="Permalink to &quot;文档问答分类&quot;">​</a></h2><p>根据上传文档类型，主要分为一下两大类：</p><ul><li>图文知识</li><li>表格知识</li></ul><h3 id="_2-1-图文知识" tabindex="-1">2.1. 图文知识 <a class="header-anchor" href="#_2-1-图文知识" aria-label="Permalink to &quot;2.1. 图文知识&quot;">​</a></h3><p>图文知识类文档问答，主要处理非表格文档，主持文档格式有：txt、doc、docx、pdf、md、xlsx。根据配置策略，图文知识也分为下面4种分类，详细为：</p><table tabindex="0"><thead><tr><th>策略分类</th><th>策略说明</th><th>支持文档格式</th></tr></thead><tbody><tr><td>通用策略</td><td>通用智能，效果均衡。适用于合同、论文、行政文书等各类文档。</td><td>本地文档：txt、doc、docx、pdf、md 在线文档：网页链接</td></tr><tr><td>说明书策略</td><td>专为家电等领域的说明书设计，智能解析复杂排版与图文内容。</td><td>本地文档：txt、doc、docx、pdf、md 在线文档：网页链接</td></tr><tr><td>Q-A对策略</td><td>高效解析Q-A对文档，适合问答清单。</td><td>本地文档：txt、doc、docx、xlsx</td></tr><tr><td>长文本策略</td><td>专为10万字以上的文档设计，记忆关联远距离上下文信息。</td><td>本地文档：txt、doc、docx、pdf、md 在线文档：网页链接</td></tr></tbody></table><h3 id="_2-2-表格知识" tabindex="-1">2.2. 表格知识 <a class="header-anchor" href="#_2-2-表格知识" aria-label="Permalink to &quot;2.2. 表格知识&quot;">​</a></h3><p>表格知识类文档问答，主要是用来处理表格数据的。说明如下：</p><table tabindex="0"><thead><tr><th>策略分类</th><th>策略说明</th><th>支持文档格式</th></tr></thead><tbody><tr><td>通用策略</td><td>智能解析Excel，支持多sheet，适用于单页单表、表头简单的表格。</td><td>本地文档：xlsx</td></tr></tbody></table><h2 id="文档问答创建使用流程" tabindex="-1">文档问答创建使用流程 <a class="header-anchor" href="#文档问答创建使用流程" aria-label="Permalink to &quot;文档问答创建使用流程&quot;">​</a></h2><p>当有本地或在线文档需要通过大模型加载使用时，可以创建文档问答来进行使用。</p><h3 id="_3-1-创建问答库" tabindex="-1">3.1. 创建问答库 <a class="header-anchor" href="#_3-1-创建问答库" aria-label="Permalink to &quot;3.1. 创建问答库&quot;">​</a></h3><p>在 “产品接入” 下的 “自定义业务” 页面中，点击”创建文档问答库“</p><p><img src="'+e+'" alt="" title="null"></p><p><img src="'+r+'" alt="" title="null"></p><p>根据需要选择对应的类别进行创建。</p><h3 id="_3-2-文档上传或配置" tabindex="-1">3.2. 文档上传或配置 <a class="header-anchor" href="#_3-2-文档上传或配置" aria-label="Permalink to &quot;3.2. 文档上传或配置&quot;">​</a></h3><ul><li>本地文档上传 进入文档问答配置页面，点击”文档管理“ ，在”本地文档”下点击”添加文档“，可以上传本地文档，注意文件格式要求说明。 <blockquote><p>部分文档问答（图文知识下 Q-A策略类文档问答、表格知识文档问答）下上传文档支持模板参考，如不清楚具体格式，可以下载模板文档进行查看。</p></blockquote></li></ul><p><img src="'+o+'" alt="" title="null"></p><ul><li>上传文档：本地文档选择加载，可以一次上传多个文档 需要注意当前策略文档问答支持的文件格式、文件大小限制</li><li>设置”标签“和描述，非必填项，可忽略</li></ul><p><img src="'+p+'" alt="" title="null"></p><ul><li>在线文档配置</li></ul><p>当创建的文档问答支持在线文档配置时，在文档管理页面，有“在线文档”选项。点击”在线文档”后点击”添加文档“，可配置需要加载的在线文档（设置的文档地址需支持外部公网访问）</p><p><img src="'+n+'" alt="" title="null"></p><ul><li><p>在“网页地址”中填写文档url，多个文档换行添加</p></li><li><p>在“更新频率”中选择更新方式，支持 ：不更新、每日更新、每周更新、每月更新</p><p>计算周期为：从设置更新频率开始计算周期</p></li><li><p>设置”标签“和描述，非必填项，可忽略</p></li></ul><p><img src="'+s+'" alt="" title="null"></p><h3 id="_3-3-文档信息设置" tabindex="-1">3.3. 文档信息设置 <a class="header-anchor" href="#_3-3-文档信息设置" aria-label="Permalink to &quot;3.3. 文档信息设置&quot;">​</a></h3><p>本地文档上传或在线文档配置后，支持操作有：</p><table tabindex="0"><thead><tr><th>操作功能</th><th>说明</th><th>支持文档类别</th></tr></thead><tbody><tr><td>文件名称</td><td>自定义文档文件名称</td><td>本地文档、在线文档</td></tr><tr><td>更新频率</td><td>重新设置在线文档更新周期</td><td>在线文档</td></tr><tr><td>标签</td><td>自定义文档文件标签说明</td><td>本地文档、在线文档</td></tr><tr><td>是否生效</td><td>设置当前文档在本文档问答中是否使用</td><td>本地文档、在线文档</td></tr><tr><td>设置分段</td><td>设置文档问答知识点拆分策略</td><td>本地文档、在线文档</td></tr><tr><td>更新</td><td>立即更新在线文档加载</td><td>在线文档</td></tr><tr><td>下载原文</td><td>下载已上传的本地文档</td><td>本地文档</td></tr><tr><td>删除</td><td>删除当前选中的文档</td><td>本地文档、在线文档</td></tr></tbody></table><p><img src="'+c+'" alt="" title="null"></p><p><img src="'+_+'" alt="" title="null"></p><p>其中“设置分段”主要提供有两种知识点拆分策略，开发者可以根据自己需要进行设置：</p><ul><li>系统默认分段</li><li>自定义分段 <ul><li>分段策略：标题分割、标识符分割</li><li>标识符策略： <ul><li>分割符：遇到指定分隔符或文本超出最大分段长度时分段，不会丢失字符。支持自定义</li><li>截断符：遇到截断符才分段。若两截断符之间的文本超过最大分段长度，将丢失超出的字符。支持自定义</li></ul></li><li>最大分段长度：[16,1024]字符区间设置</li></ul></li></ul><p><img src="'+h+'" alt="" title="null"></p><h3 id="_3-4-知识点管理" tabindex="-1">3.4. 知识点管理 <a class="header-anchor" href="#_3-4-知识点管理" aria-label="Permalink to &quot;3.4. 知识点管理&quot;">​</a></h3><p>在实际使用中，如果文档文档抽取的知识点不准确（多抽、少抽）、或无法问答、或不需要，可以通过知识点管理进行自定义编排处理。</p><p><img src="'+m+'" alt="" title="null"></p><ul><li>查看：预览整个文档，查看当前知识点对应的问题和答案，可配置当前知识点是否使用，但不可修改知识点信息（关联问题和结果信息）</li><li>编辑：预览整个文档，查看当前知识点对应的问题和答案，可配置当前知识点是否使用，可修改知识点信息（关联问题和结果信息）</li><li>知识点配置开关：控制当前知识点是否配置使用</li></ul><p><img src="'+u+'" alt="" title="null"></p><h3 id="_3-5-构建发布和配置使用" tabindex="-1">3.5. 构建发布和配置使用 <a class="header-anchor" href="#_3-5-构建发布和配置使用" aria-label="Permalink to &quot;3.5. 构建发布和配置使用&quot;">​</a></h3><p>点击“构建发布”即可发布文档问答上线，发布成功后可以在AIUI应用下大模型下配置发布的文档问答。</p><p><img src="'+b+'" alt="" title="null"></p><p><img src="'+x+'" alt="" title="null"></p><p><img src="'+g+'" alt="" title="null"></p>',48)])])}const Q=l(q,[["render",f]]);export{I as __pageData,Q as default};
